using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Implementado pelo balão de diálogo (Etapa 2). Se o NPC não tiver nenhum
/// componente que implemente esta interface atribuído em "Dialogue Display",
/// Action_Dialogue usa Debug.Log como alternativa.
/// </summary>
public interface INpcDialogueDisplay
{
    /// <summary>
    /// Mostra uma linha de diálogo (com efeito de escrita animado, suportando
    /// paginação e as tags do DialogueMarkupParser) e espera terminar —
    /// incluindo a espera pelo botão de interação no fim de cada página.
    /// </summary>
    /// <param name="speakerName">Nome a mostrar como falante (pode ser vazio).</param>
    /// <param name="speakerTransform">
    /// Transform do falante desta linha (NPC, player, ou outro NPC — ver
    /// DialogueLine.ResolveSpeakerTransform), usado por implementações que
    /// desenhem uma calda a apontar para o falante (Etapa 8). Pode ser null.
    /// </param>
    IEnumerator ShowLine(NpcController npc, string speakerName, string text, float charsPerSecond, Transform speakerTransform);

    /// <summary>Esconde o balão de diálogo.</summary>
    void Hide(NpcController npc);
}

/// <summary>
/// Implementado pelo menu de escolhas (Etapa 2). Devolve, via callback, o
/// índice da escolha seleccionada (-1 se nenhuma).
/// </summary>
public interface INpcChoiceMenu
{
    IEnumerator Show(NpcController npc, List<NpcChoice> choices, Action<int> onSelected);
}

/// <summary>Uma opção apresentada ao player numa Action_ShowChoices.</summary>
[System.Serializable]
public class NpcChoice
{
    public string text;

    [Tooltip("ID do NpcEvent a activar quando esta escolha for seleccionada (esse evento dispara sem precisar de condição própria).")]
    public string targetEventId;
}
